#include <iostream>
#include <cmath>

class Point {
private:
    int x;
    int y;

public:
    void setCoordinates(int _x, int _y) {
        x = _x;
        y = _y;
    }

    double getDistanceToOrigin() {
        return std::sqrt(x * x + y * y);
    }
};

int main() {
    Point p;
    int x_val, y_val;
    char comma;
    while (std::cin >> x_val >> comma >> y_val) {
        p.setCoordinates(x_val, y_val);
        double dist = p.getDistanceToOrigin();
        // Print with sufficient precision for comparison
        std::cout.precision(12);
        std::cout << std::fixed << dist << std::endl;
    }
    return 0;
}
